class Solution:
    def matrixSum(self, nums: list[list[int]]) -> int:
        for row in nums:
            row.sort()
        score = 0
        m = len(nums)
        n = len(nums[0]) if nums else 0
        for col in range(n):
            max_val = max(nums[r][col] for r in range(m))
