class Solution:
    def punishmentNumber(self, n: int) -> int:
        def can_partition(s, target):
            if not s and target == 0:
                return True
            if target < 0:
                return False
            for i in range(1, len(s) + 1):
                if can_partition(s[i:], target - int(s[:i])):
                    return True
            return False

        result = 0
        for i in range(1, n + 1):
            sq = i * i
            if can_partition(str(sq), i):
                result += sq
        return result

class Solution:
    def paintWalls(self, cost: list[int], time: list[int]) -> int:
        n = len(cost)
        INF = float('inf')
        # dp[j] = min cost to cover j walls
        dp = [0] + [INF] * n
        for i in range(n):
            ndp = dp[:]
            for j in range(1, n + 1):
                if dp[max(0, j - time[i] - 1)] != INF:
                    ndp[j] = min(ndp[j], dp[max(0, j - time[i] - 1)] + cost[i])
            dp = ndp
        return dp[n]

class Solution:
    def minCost(self, nums: list[int], x: int) -> int:
        n = len(nums)
        min_cost = nums[:]
        result = sum(min_cost)
        for k in range(1, n):
            for i in range(n):
                j = (i + k) % n
                if nums[j] < min_cost[i]:
                    min_cost[i] = nums[j]
            total = sum(min_cost) + k * x
            if total < result:
                result = total
        return result

