class Solution:
    def specialPerm(self, nums: list[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)
        dp = [[0] * n for _ in range(1 << n)]
        for i in range(n):
            dp[1 << i][i] = 1
        for mask in range(1 << n):
            for last in range(n):
                if dp[mask][last] == 0:
                    continue
                for nxt in range(n):
                    if mask & (1 << nxt):
                        continue
                    if nums[last] % nums[nxt] == 0 or nums[nxt] % nums[last] == 0:
                        dp[mask | (1 << nxt)][nxt] = (dp[mask | (1 << nxt)][nxt] + dp[mask][last]) % MOD
        full = (1 << n) - 1
        return sum(dp[full][i] for i in range(n)) % MOD

class Solution:
    def sumImbalanceNumbers(self, nums: list[int]) -> int:
        n = len(nums)
        total = 0
        for i in range(n):
            present = set()
            imbalance = 0
            for j in range(i, n):
                v = nums[j]
                if v not in present:
                    has_left = (v - 1) in present
                    has_right = (v + 1) in present
                    if has_left and has_right:
                        imbalance -= 1
                    elif not has_left and not has_right and present:
                        imbalance += 1
                    present.add(v)
                total += imbalance
        return total

