class Solution:
    def longestAlternatingSubarray(self, nums: list[int], threshold: int) -> int:
        n = len(nums)
        best = 0
        for i in range(n):
            if nums[i] % 2 != 0 or nums[i] > threshold:
                continue
            length = 1
            for j in range(i + 1, n):
                if nums[j] > threshold or nums[j] % 2 == nums[j - 1] % 2:
                    break
                length += 1
            best = max(best, length)
        return best

class Solution:
    def numberOfGoodSubarraySplits(self, nums: list[int]) -> int:
        MOD = 10**9 + 7
        ones = [i for i, x in enumerate(nums) if x == 1]
        if len(ones) == 0:
            return 0
        result = 1
        for i in range(1, len(ones)):
            result = (result * (ones[i] - ones[i - 1])) % MOD
        return result

from collections import deque

class Solution:
    def continuousSubarrays(self, nums: list[int]) -> int:
        n = len(nums)
        max_dq = deque()
        min_dq = deque()
        left = 0
        count = 0
        for right in range(n):
            while max_dq and nums[max_dq[-1]] <= nums[right]:
                max_dq.pop()
            max_dq.append(right)
            while min_dq and nums[min_dq[-1]] >= nums[right]:
                min_dq.pop()
            min_dq.append(right)
            while nums[max_dq[0]] - nums[min_dq[0]] > 2:
                left += 1
                while max_dq[0] < left:
                    max_dq.popleft()
                while min_dq[0] < left:
                    min_dq.popleft()
            count += right - left + 1
        return count

class Solution:
    def alternatingSubarray(self, nums: list[int]) -> int:
        n = len(nums)
        result = -1
        for i in range(n):
            for j in range(i + 1, n):
                expected = nums[i] + (1 if (j - i) % 2 == 1 else 0)
                if nums[j] == expected:
                    result = max(result, j - i + 1)
                else:
                    break
        return result

