from itertools import permutations

class Solution:
    def minimumString(self, a: str, b: str, c: str) -> str:
        def merge(s1, s2):
            if s2 in s1:
                return s1
            if s1 in s2:
                return s2
            max_overlap = 0
            for i in range(1, min(len(s1), len(s2)) + 1):
                if s1[-i:] == s2[:i]:
                    max_overlap = i
            return s1 + s2[max_overlap:]

        best = None
        for x, y, z in permutations([a, b, c]):
            merged = merge(merge(x, y), z)
            if best is None or len(merged) < len(best) or (len(merged) == len(best) and merged < best):
                best = merged
        return best

class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        n = len(s)

        # Precompute cost[i][j] = min changes to make s[i..j] a semi-palindrome
        cost = [[0] * n for _ in range(n)]
        for i in range(n):
            for j in range(i + 1, n):
                length = j - i + 1
                min_cost = float('inf')
                for d in range(1, length):
                    if length % d != 0:
                        continue
                    changes = 0
                    group_size = length // d
                    for g in range(d):
                        left = i + g
                        right = i + g + (group_size - 1) * d
                        while left < right:
                            if s[left] != s[right]:
                                changes += 1
                            left += d
                            right -= d
                    min_cost = min(min_cost, changes)
                cost[i][j] = min_cost

        # DP: dp[i][p] = min changes to partition first i chars into p parts
        INF = float('inf')
        dp = [[INF] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0

        for i in range(1, n + 1):
            for p in range(1, min(i, k) + 1):
                for t in range(p - 1, i - 1):
                    if i - t >= 2:
                        val = dp[t][p - 1] + cost[t][i - 1]
                        if val < dp[i][p]:
                            dp[i][p] = val

        return dp[n][k]

