class Solution:
    def numberOfWays(self, n: int, x: int) -> int:
        MOD = 10**9 + 7
        dp = [0] * (n + 1)
        dp[0] = 1
        i = 1
        while True:
            power = i ** x
            if power > n:
                break
            for j in range(n, power - 1, -1):
                dp[j] = (dp[j] + dp[j - power]) % MOD
            i += 1
        return dp[n]

class Solution:
    def minimumBeautifulSubstrings(self, s: str) -> int:
        # Precompute powers of 5 in binary representation
        powers = set()
        for i in range(15):
            val = 5 ** i
            if val > 2 ** 15:
                break
            powers.add(bin(val)[2:])

        n = len(s)
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[n] = 0

        for i in range(n - 1, -1, -1):
            if s[i] == '0':
                continue
            for j in range(i + 1, n + 1):
                substr = s[i:j]
                if substr in powers and dp[j] != INF:
                    dp[i] = min(dp[i], 1 + dp[j])

        return dp[0] if dp[0] != INF else -1

