class Solution:
    def numberOfBeautifulIntegers(self, low: int, high: int, k: int) -> int:
        def count(n):
            if n <= 0:
                return 0
            s = str(n)
            from functools import lru_cache

            @lru_cache(None)
            def dp(pos, diff, rem, tight, started):
                if pos == len(s):
                    return 1 if (started and diff == 0 and rem == 0) else 0

                limit = int(s[pos]) if tight else 9
                result = 0
                for d in range(0, limit + 1):
                    next_tight = tight and (d == limit)
                    if not started and d == 0:
                        result += dp(pos + 1, diff, rem, next_tight, False)
                    else:
                        new_diff = diff + (1 if d % 2 == 0 else -1)
                        new_rem = (rem * 10 + d) % k
                        result += dp(pos + 1, new_diff, new_rem, next_tight, True)
                return result

            ans = dp(0, 0, 0, True, False)
            dp.cache_clear()
            return ans

        return count(high) - count(low - 1)

