class Solution:
    def minOperations(self, nums: List[int], target: int) -> int:
        total = sum(nums)
        if total < target:
            return -1

        cnt = [0] * 32
        for num in nums:
            cnt[num.bit_length() - 1] += 1

        ops = 0

        for i in range(31):
            if (target >> i) & 1:
                if cnt[i] > 0:
                    cnt[i] -= 1
                else:
                    j = i + 1
                    while j < 32 and cnt[j] == 0:
                        j += 1
                    for k in range(j, i, -1):
                        cnt[k] -= 1
                        cnt[k - 1] += 2
                        ops += 1
                    cnt[i] -= 1

            cnt[i + 1] += cnt[i] // 2

        return ops

