        n = len(s)
        min_len = n + 1

        # First pass: find minimum length of beautiful substring
        for i in range(n):
            ones = 0
            for j in range(i, n):
                if s[j] == '1':
                    ones += 1
                if ones == k:
                    min_len = min(min_len, j - i + 1)
                    break

        if min_len == n + 1:
            return ""

        # Second pass: find lexicographically smallest of min_len
        best = None
        for i in range(n - min_len + 1):
            sub = s[i:i + min_len]
            if sub.count('1') == k:
                if best is None or sub < best:
                    best = sub

        return best

