class Solution:
    def maxBalancedSubsequenceSum(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0

        # b[i] = nums[i] - i, need non-decreasing b subsequence maximizing sum
        b_vals = sorted(set(nums[i] - i for i in range(n)))
        size = len(b_vals)
        NEG_INF = -10**18
        bit = [NEG_INF] * (size + 1)

        def query(idx):
            res = NEG_INF
            while idx > 0:
                if bit[idx] > res:
                    res = bit[idx]
                idx -= idx & (-idx)
            return res

        def update(idx, val):
            while idx <= size:
                if val > bit[idx]:
                    bit[idx] = val
                idx += idx & (-idx)

        result = max(nums)
        for i in range(n):
            b = nums[i] - i
            compressed = bisect.bisect_left(b_vals, b) + 1
            best = query(compressed)
            if best == NEG_INF:
                current_sum = nums[i]
            else:
                current_sum = best + nums[i]
            if nums[i] > current_sum:
                current_sum = nums[i]
            if current_sum > result:
                result = current_sum
            update(compressed, current_sum)

        return result

