class Solution:
    def minimumCost(self, nums: List[int]) -> int:
        nums.sort()
        n = len(nums)
        candidates = set()
        if n % 2 == 1:
            candidates = self._nearby_pals(nums[n // 2])
        else:
            candidates = self._nearby_pals(nums[n // 2 - 1]) | self._nearby_pals(nums[n // 2])
        valid = [c for c in candidates if 1 <= c < 10**9]
        return min(sum(abs(x - p) for x in nums) for p in valid)

    def _nearby_pals(self, n):
        pals = set()
        s = str(n)
        L = len(s)
        if L > 1:
            pals.add(10**(L-1) - 1)
        pals.add(10**L + 1)
        if L % 2 == 0:
            half_len = L // 2
            half_val = int(s[:half_len])
            for d in [-1, 0, 1]:
                hv = half_val + d
                hs = str(hv)
                if len(hs) == half_len and hv > 0:
                    pals.add(int(hs + hs[::-1]))
                elif len(hs) < half_len:
                    pals.add(10**(L-1) - 1)
                elif len(hs) > half_len:
                    pals.add(10**L + 1)
        else:
            half_len = (L + 1) // 2
            half_val = int(s[:half_len])
            for d in [-1, 0, 1]:
                hv = half_val + d
                hs = str(hv)
                if len(hs) == half_len and hv > 0:
                    pals.add(int(hs + hs[-2::-1]))
                elif len(hs) < half_len:
                    pals.add(10**(L-1) - 1)
                elif len(hs) > half_len:
                    pals.add(10**L + 1)
        return pals

