class Solution:
    def minimumOperationsToMakeEqual(self, x: int, y: int) -> int:
        if x == y:
            return 0
        visited = set()
        queue = deque([(x, 0)])
        visited.add(x)
        while queue:
            cur, steps = queue.popleft()
            candidates = [cur + 1, cur - 1]
            if cur % 11 == 0:
                candidates.append(cur // 11)
            if cur % 5 == 0:
                candidates.append(cur // 5)
            for nxt in candidates:
                if nxt == y:
                    return steps + 1
                if nxt not in visited and 0 < nxt <= max(x, y) * 2 + 10:
                    visited.add(nxt)
                    queue.append((nxt, steps + 1))
        return abs(x - y)

class Solution:
    def findMaximumNumber(self, k: int, x: int) -> int:
        def price_sum(num):
            total = 0
            bit_pos = x
            while bit_pos <= 64:
                b = bit_pos - 1
                cycle = 1 << (b + 1)
                full = (num + 1) // cycle
                rem = (num + 1) % cycle
                cnt = full * (1 << b) + max(0, rem - (1 << b))
                total += cnt
                bit_pos += x
            return total

        lo, hi = 1, 10**18
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if price_sum(mid) <= k:
                lo = mid
            else:
                hi = mid - 1
        return lo

