class Solution:
    def maxPalindromesAfterOperations(self, words: List[str]) -> int:
        total = Counter()
        for w in words:
            total.update(w)

        pairs = sum(v // 2 for v in total.values())
        singles = sum(v % 2 for v in total.values())

        word_lens = sorted(len(w) for w in words)

        count = 0
        for L in word_lens:
            pairs_needed = L // 2
            if L % 2 == 0:
                if pairs >= pairs_needed:
                    pairs -= pairs_needed
                    count += 1
            else:
                if singles > 0:
                    if pairs >= pairs_needed:
                        pairs -= pairs_needed
                        singles -= 1
                        count += 1
                else:
                    if pairs >= pairs_needed + 1:
                        pairs -= (pairs_needed + 1)
                        singles += 1
                        count += 1

        return count

