class Solution:
    def minOperations(self, k: int) -> int:
        if k <= 1:
            return 0
        best = k  # worst case: increase by k-1, no duplicates
        for v in range(1, k + 1):
            c = math.ceil(k / v)
            ops = (v - 1) + (c - 1)
            if ops < best:
                best = ops
        return best

