class Solution:
    def mostFrequentIDs(self, nums: List[int], freq: List[int]) -> List[int]:
        id_count = defaultdict(int)
        heap = []
        result = []

        for i in range(len(nums)):
            id_count[nums[i]] += freq[i]
            new_count = id_count[nums[i]]
            if new_count > 0:
                heapq.heappush(heap, (-new_count, nums[i]))

            while heap:
                neg_count, uid = heap[0]
                current = id_count.get(uid, 0)
                if -neg_count != current:
                    heapq.heappop(heap)
                else:
                    break

            result.append(-heap[0][0] if heap else 0)

        return result

