class Solution:
    def minimumValueSum(self, nums: List[int], andValues: List[int]) -> int:
        n = len(nums)
        m = len(andValues)
        INF = float('inf')

        # prev_row[i] = min cost to divide nums[0..i-1] into j groups
        prev_row = [INF] * (n + 1)
        prev_row[0] = 0

        for j in range(m):
            new_row = [INF] * (n + 1)
            # and_map: {AND value -> min prev_row[start] for all starts
            # that produce this AND with nums[start..i-1]}
            and_map = {}

            for i in range(j + 1, n + 1):
                # Extend existing subarrays by nums[i-1]
                new_and_map = {}
                for and_val, min_prev in and_map.items():
                    new_and = and_val & nums[i - 1]
                    if new_and not in new_and_map or min_prev < new_and_map[new_and]:
                        new_and_map[new_and] = min_prev

                # Start new subarray at position i-1 (single element)
                if prev_row[i - 1] != INF:
                    val = nums[i - 1]
                    if val not in new_and_map or prev_row[i - 1] < new_and_map[val]:
                        new_and_map[val] = prev_row[i - 1]

                and_map = new_and_map

                target = andValues[j]
                if target in and_map:
                    new_row[i] = and_map[target] + nums[i - 1]

            prev_row = new_row

        result = prev_row[n]
        return result if result != INF else -1

