class Solution:
    def findKthSmallest(self, coins: List[int], k: int) -> int:
        def lcm(a, b):
            return a * b // gcd(a, b)

        def count(x):
            n = len(coins)
            total = 0
            for mask in range(1, 1 << n):
                l = 1
                bits = 0
                overflow = False
                for i in range(n):
                    if mask & (1 << i):
                        bits += 1
                        l = lcm(l, coins[i])
                        if l > x:
                            overflow = True
                            break
                if not overflow:
                    if bits % 2 == 1:
                        total += x // l
                    else:
                        total -= x // l
            return total

        lo, hi = 1, min(coins) * k
        while lo < hi:
            mid = (lo + hi) // 2
            if count(mid) < k:
                lo = mid + 1
            else:
                hi = mid
        return lo

