class Solution:
    def findProductsOfElements(self, queries: List[List[int]]) -> List[int]:

        def count_total_bits(n):
            """Total set bits in binary representations of 1, 2, ..., n."""
            if n <= 0:
                return 0
            total = 0
            for k in range(61):
                p = 1 << (k + 1)
                full = (n + 1) // p * (1 << k)
                rem = (n + 1) % p
                partial = max(0, rem - (1 << k))
                total += full + partial
            return total

        def total_exp(n):
            """Sum of bit-position indices for all set bits in 1..n.
            This equals the total exponent sum for the product of all elements."""
            if n <= 0:
                return 0
            total = 0
            for k in range(61):
                p = 1 << (k + 1)
                full = (n + 1) // p * (1 << k)
                rem = (n + 1) % p
                partial = max(0, rem - (1 << k))
                total += k * (full + partial)
            return total

        def find_number(pos):
            """Find number m such that pos-th element of big_nums is in m's powerful array.
            Returns (m, offset_within_m)."""
            lo, hi = 1, 2
            while count_total_bits(hi) <= pos:
                hi *= 2
            while lo < hi:
                mid = (lo + hi) // 2
                if count_total_bits(mid) <= pos:
                    lo = mid + 1
                else:
                    hi = mid
            return lo, pos - count_total_bits(lo - 1)

        def partial_exp_in_number(n, a, b):
            """Sum of bit positions for the a-th through b-th set bits of n."""
            result = 0
            idx = 0
            for k in range(61):
                if n & (1 << k):
                    if a <= idx <= b:
                        result += k
                    idx += 1
            return result

        def range_exp(l, r):
            """Sum of exponents for big_nums[l..r] (0-indexed)."""
            if l > r:
                return 0
            m_l, off_l = find_number(l)
            m_r, off_r = find_number(r)

            if m_l == m_r:
                return partial_exp_in_number(m_l, off_l, off_r)

            result = partial_exp_in_number(m_l, off_l, 10**9)
            if m_l + 1 <= m_r - 1:
                result += total_exp(m_r - 1) - total_exp(m_l)
            result += partial_exp_in_number(m_r, 0, off_r)
            return result

        ans = []
        for from_i, to_i, mod_i in queries:
            s = range_exp(from_i, to_i)
            ans.append(pow(2, s, mod_i))
        return ans

