class Solution:
    def minimumDifference(self, nums: List[int], k: int) -> int:
        ans = float('inf')
        prev = set()
        for num in nums:
            curr = {num}
            for v in prev:
                curr.add(num | v)
            for v in curr:
                diff = abs(v - k)
                if diff < ans:
                    ans = diff
            prev = curr
        return ans

