class Solution:
    def maxTotalReward(self, rewardValues: List[int]) -> int:
        rewardValues.sort()
        max_val = max(rewardValues)
        dp = [False] * (2 * max_val)
        dp[0] = True
        for v in rewardValues:
            for s in range(v - 1, -1, -1):
                if dp[s]:
                    dp[s + v] = True
        for s in range(2 * max_val - 1, -1, -1):
            if dp[s]:
                return s
        return 0

