class Solution:
    def clearDigits(self, s: str) -> str:
        stack = []
        for ch in s:
            if ch.isdigit():
                if stack:
                    stack.pop()
            else:
                stack.append(ch)
        return ''.join(stack)

class Solution:
    def numberOfChild(self, n: int, k: int) -> int:
        period = 2 * (n - 1)
        r = k % period
        if r < n:
            return r
        else:
            return period - r

class Solution:
    def compressedString(self, word: str) -> str:
        comp = []
        i = 0
        n = len(word)
        while i < n:
            c = word[i]
            count = 0
            while i + count < n and word[i + count] == c and count < 9:
                count += 1
            comp.append(str(count))
            comp.append(c)
            i += count
        return ''.join(comp)

