class Solution:
    def validStrings(self, n: int) -> List[str]:
        if n == 1:
            return ["0", "1"]

        result = []

        def backtrack(curr):
            if len(curr) == n:
                result.append(curr)
                return
            if curr and curr[-1] == '0':
                backtrack(curr + '1')
            else:
                backtrack(curr + '0')
                backtrack(curr + '1')

        backtrack("")
        return result

