class Solution:
    def maximumLength(self, nums: List[int], k: int) -> int:
        dp = [dict() for _ in range(k + 1)]
        best = [0] * (k + 1)
        for num in nums:
            for j in range(k, -1, -1):
                same = dp[j].get(num, 0) + 1
                trans = best[j - 1] + 1 if j > 0 else 1
                dp[j][num] = max(same, trans)
                best[j] = max(best[j], dp[j][num])
        return best[k]

