class Solution:
    def numberOfPermutations(self, n: int, requirements: List[List[int]]) -> int:
        MOD = 10**9 + 7
        req = {end: cnt for end, cnt in requirements}
        max_inv = max(cnt for _, cnt in requirements)

        dp = [0] * (max_inv + 1)
        dp[0] = 1

        for i in range(n):
            new_dp = [0] * (max_inv + 1)
            prefix = [0] * (max_inv + 2)
            for inv in range(max_inv + 1):
                prefix[inv + 1] = (prefix[inv] + dp[inv]) % MOD

            for inv in range(max_inv + 1):
                lo = max(0, inv - i)
                new_dp[inv] = (prefix[inv + 1] - prefix[lo]) % MOD

            if i in req:
                required = req[i]
                for inv in range(max_inv + 1):
                    if inv != required:
                        new_dp[inv] = 0

            dp = new_dp

        final_req = req.get(n - 1, 0)
        return dp[final_req] % MOD

