class Solution:
    def maximumTotalCost(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0
        pos = nums[0]  # dp[i][0]: current element at even offset (+ sign)
        neg = float('-inf')  # dp[i][1]: current element at odd offset (- sign)
        for i in range(1, n):
            new_pos = max(pos, neg) + nums[i]
            new_neg = pos - nums[i]
            pos = new_pos
            neg = new_neg
        return max(pos, neg)

