class Solution:
    def maxHeightOfTriangle(self, red: int, blue: int) -> int:
        def max_height(c1, c2):
            h = 0
            row = 1
            while True:
                if row % 2 == 1:
                    if c1 >= row:
                        c1 -= row
                        h += 1
                        row += 1
                    else:
                        break
                else:
                    if c2 >= row:
                        c2 -= row
                        h += 1
                        row += 1
                    else:
                        break
            return h

        return max(max_height(red, blue), max_height(blue, red))

