        n = len(nums)
        ops = 0
        nums = nums[:]
        for i in range(n - 2):
            if nums[i] == 0:
                ops += 1
                nums[i] ^= 1
                nums[i + 1] ^= 1
                nums[i + 2] ^= 1
        if nums[-1] == 1 and nums[-2] == 1:
            return ops
        return -1

