class Solution:
    def canReachCorner(self, xCorner: int, yCorner: int, circles: List[List[int]]) -> bool:
        n = len(circles)
        parent = list(range(n))
        rank = [0] * n

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(x, y):
            px, py = find(x), find(y)
            if px == py:
                return
            if rank[px] < rank[py]:
                px, py = py, px
            parent[py] = px
            if rank[px] == rank[py]:
                rank[px] += 1

        valid = []
        for i in range(n):
            cx, cy, r = circles[i]
            closest_x = max(0, min(cx, xCorner))
            closest_y = max(0, min(cy, yCorner))
            dx = cx - closest_x
            dy = cy - closest_y
            if dx * dx + dy * dy > r * r:
                continue
            if cx * cx + cy * cy <= r * r:
                return False
            dx2 = cx - xCorner
            dy2 = cy - yCorner
            if dx2 * dx2 + dy2 * dy2 <= r * r:
                return False
            valid.append(i)

        for ii in range(len(valid)):
            for jj in range(ii + 1, len(valid)):
                i, j = valid[ii], valid[jj]
                cx1, cy1, r1 = circles[i]
                cx2, cy2, r2 = circles[j]
                dx = cx1 - cx2
                dy = cy1 - cy2
                if dx * dx + dy * dy <= (r1 + r2) * (r1 + r2):
                    union(i, j)

        comp_edges = defaultdict(lambda: [False, False, False, False])
        for i in valid:
            cx, cy, r = circles[i]
            root = find(i)
            if cx <= r:
                comp_edges[root][0] = True
            if cy <= r:
                comp_edges[root][1] = True
            if cx + r >= xCorner:
                comp_edges[root][2] = True
            if cy + r >= yCorner:
                comp_edges[root][3] = True

        for edges in comp_edges.values():
            left, bottom, right, top = edges
            if left and right:
                return False
            if left and top:
                return False
            if left and bottom:
                return False
            if bottom and top:
                return False
            if right and top:
                return False

        return True

class Solution:
    def getSmallestString(self, s: str) -> str:
        s_list = list(s)
        for i in range(len(s_list) - 1):
            a = int(s_list[i])
            b = int(s_list[i + 1])
            if a % 2 == b % 2 and a > b:
                s_list[i], s_list[i + 1] = s_list[i + 1], s_list[i]
                return ''.join(s_list)
        return s

