class Solution:
    def numberOfSubmatrices(self, grid: List[List[str]]) -> int:
        n, m = len(grid), len(grid[0])
        prex = [[0] * (m + 1) for _ in range(n + 1)]
        prey = [[0] * (m + 1) for _ in range(n + 1)]

        count = 0
        for i in range(n):
            for j in range(m):
                prex[i + 1][j + 1] = prex[i][j + 1] + prex[i + 1][j] - prex[i][j] + (1 if grid[i][j] == 'X' else 0)
                prey[i + 1][j + 1] = prey[i][j + 1] + prey[i + 1][j] - prey[i][j] + (1 if grid[i][j] == 'Y' else 0)

                if prex[i + 1][j + 1] == prey[i + 1][j + 1] and prex[i + 1][j + 1] >= 1:
                    count += 1

        return count

