class Solution:
    def minNumberOfSeconds(self, mountainHeight: int, workerTimes: list) -> int:
        def can_reduce(T):
            total = 0
            for w in workerTimes:
                # w * x * (x+1) / 2 <= T
                # x^2 + x - 2T/w <= 0
                # x = (-1 + sqrt(1 + 8T/w)) // 2
                val = 2 * T // w
                # solve x^2 + x - val <= 0
                import math
                x = int((-1 + math.isqrt(1 + 4 * val)) // 2)
                if x < 0:
                    x = 0
                total += x
                if total >= mountainHeight:
                    return True
            return total >= mountainHeight

        lo, hi = 1, max(workerTimes) * mountainHeight * (mountainHeight + 1) // 2
        while lo < hi:
            mid = (lo + hi) // 2
            if can_reduce(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

class Solution:
    def numberOfSubstrings(self, s: str, k: int) -> int:
        n = len(s)
        count = [0] * 26
        result = 0
        right = 0
        freq_k = 0
        for left in range(n):
            while right < n and freq_k == 0:
                idx = ord(s[right]) - ord('a')
                count[idx] += 1
                if count[idx] == k:
                    freq_k += 1
                right += 1
            if freq_k > 0:
                result += n - right + 1
            else:
                break
            idx = ord(s[left]) - ord('a')
            if count[idx] == k:
                freq_k -= 1
            count[idx] -= 1
        return result

import math

class Solution:
    def nonSpecialCount(self, l: int, r: int) -> int:
        # A number is "special" if it has exactly 2 proper divisors.
        # This is true iff the number is p^2 where p is prime
        # (proper divisors of p^2 are: 1 and p)
        # So count non-special = (r - l + 1) - count of prime squares in [l, r]

        a = math.isqrt(l)
        if a * a < l:
            a += 1
        b = math.isqrt(r)

        if a > b:
            return r - l + 1

        # Sieve of Eratosthenes up to b
        if b < 2:
            return r - l + 1

        is_prime = [True] * (b + 1)
        is_prime[0] = is_prime[1] = False
        for i in range(2, int(b ** 0.5) + 1):
            if is_prime[i]:
                for j in range(i * i, b + 1, i):
                    is_prime[j] = False

        prime_count = sum(1 for p in range(a, b + 1) if is_prime[p])
        return (r - l + 1) - prime_count

class Solution:
    def minChanges(self, n: int, k: int) -> int:
        # Can only change 1-bits in n to 0.
        # If k has a 1-bit where n has 0, impossible.
        if (n & k) != k:
            return -1
        # Count bits in n that differ from k
        return bin(n ^ k).count('1')

