class Solution:
    def resultsArray(self, nums: List[int], k: int) -> List[int]:
        n = len(nums)
        if k == 1:
            return nums[:]

        result = []
        consec = 1
        for i in range(1, n):
            if nums[i] == nums[i - 1] + 1:
                consec += 1
            else:
                consec = 1
            if i >= k - 1:
                if consec >= k:
                    result.append(nums[i])
                else:
                    result.append(-1)

        return result

