class Solution:
    def findMaximumScore(self, nums: List[int]) -> int:
        n = len(nums)
        score = 0
        i = 0
        while i < n - 1:
            j = i + 1
            while j < n - 1 and nums[j] < nums[i]:
                j += 1
            score += (j - i) * nums[i]
            i = j
