class Solution:
    def countOfPairs(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)
        if n == 0:
            return 0
        max_val = max(nums)

        dp = [0] * (max_val + 1)
        for j in range(nums[0] + 1):
            dp[j] = 1

        for i in range(1, n):
            diff = max(0, nums[i] - nums[i - 1])
            prefix = [0] * (max_val + 2)
            for j in range(max_val + 1):
                prefix[j + 1] = (prefix[j] + dp[j]) % MOD

            new_dp = [0] * (max_val + 1)
            for j in range(nums[i] + 1):
                upper = min(j - diff, nums[i - 1])
                if upper >= 0:
                    new_dp[j] = prefix[upper + 1]
            dp = new_dp

        return sum(dp) % MOD

class Solution:
    def stringHash(self, s: str, k: int) -> str:
        result = []
        n = len(s)
        for i in range(0, n, k):
            substring = s[i:i+k]
            total = sum(ord(c) - ord('a') for c in substring)
            hashed_char = total % 26
            result.append(chr(hashed_char + ord('a')))
        return ''.join(result)

