from itertools import product as iprod


class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        half_len = (n + 1) // 2
        seen = set()

        # Precompute factorials
        fact = [1] * (n + 1)
        for i in range(1, n + 1):
            fact[i] = fact[i - 1] * i

        # Generate all k-palindromic n-digit integers
        for half in iprod(range(10), repeat=half_len):
            if half[0] == 0:
                continue
            # Construct full palindrome
            if n % 2 == 0:
                full = half + half[::-1]
            else:
                full = half + half[:-1][::-1]

            # Check divisibility by k
            num = 0
            for d in full:
                num = num * 10 + d
            if num % k != 0:
                continue

            # Use sorted tuple as canonical form (deduplicate digit multisets)
            seen.add(tuple(sorted(full)))

        # Count valid permutations for each unique digit multiset
        total = 0
        for dt in seen:
            counts = [0] * 10
            for d in dt:
                counts[d] += 1
            denom = 1
            for c in counts:
                denom *= fact[c]
            # Permutations without leading zero = (n-1)! * (n - zeros) / product of factorials
            total += fact[n - 1] * (n - counts[0]) // denom

        return total

