class Solution:
    def maximumValueSum(self, board: List[List[int]]) -> int:
        m = len(board)
        n = len(board[0])

        # For each row, get top 3 values with their columns
        row_top3 = []
        for i in range(m):
            top3 = []
            for j in range(n):
                val = board[i][j]
                if len(top3) < 3:
                    top3.append((val, j))
                    top3.sort(reverse=True)
                elif val > top3[2][0]:
                    top3[2] = (val, j)
                    top3.sort(reverse=True)
            row_top3.append(top3)

        ans = float('-inf')
        # Try all combinations of 3 rows
        for r1, r2, r3 in combinations(range(m), 3):
            for v1, c1 in row_top3[r1]:
                for v2, c2 in row_top3[r2]:
                    if c2 == c1:
                        continue
                    for v3, c3 in row_top3[r3]:
                        if c3 == c1 or c3 == c2:
                            continue
                        ans = max(ans, v1 + v2 + v3)

        return ans

class Solution:
    def largestPalindrome(self, n: int, k: int) -> str:
        h = (n + 1) // 2

        if k == 1:
            return '9' * n

        # Precompute powers of 10 mod k
        pow10 = [1] * n
        for i in range(1, n):
            pow10[i] = (pow10[i - 1] * 10) % k

        # Weight of each digit position in the first half
        # Each digit a[j] contributes to palindrome value mod k
        weight = [0] * h
        for j in range(h):
            mirror = n - 1 - j
            if mirror == j:
                weight[j] = pow10[j] % k
            else:
                weight[j] = (pow10[n - 1 - j] + pow10[j]) % k

        # DP: dp[i][r] = True if positions i..h-1 can achieve sum % k == r
        dp = [[False] * k for _ in range(h + 1)]
        dp[h][0] = True

        for i in range(h - 1, -1, -1):
            digits = range(9, 0, -1) if i == 0 else range(9, -1, -1)
            for d in digits:
                w = (d * weight[i]) % k
                for r in range(k):
                    if dp[i + 1][r]:
                        dp[i][(r + w) % k] = True

        # Greedy construction: maximize each digit left to right
        result = []
        req = 0
        for i in range(h):
            digits = range(9, 0, -1) if i == 0 else range(9, -1, -1)
            for d in digits:
                w = (d * weight[i]) % k
                new_req = (req - w) % k
                if dp[i + 1][new_req]:
                    result.append(str(d))
                    req = new_req
                    break

        first_half = ''.join(result)
        if n % 2 == 0:
            return first_half + first_half[::-1]
        else:
            return first_half + first_half[:-1][::-1]

