class Solution:
    def minValidStrings(self, words: List[str], target: str) -> int:
        # Build trie from all words
        trie = {}
        for word in words:
            node = trie
            for ch in word:
                if ch not in node:
                    node[ch] = {}
                node = node[ch]

        n = len(target)
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[0] = 0

        for i in range(n):
            if dp[i] == INF:
                continue
            node = trie
            j = i
            while j < n and target[j] in node:
                node = node[target[j]]
                j += 1
                if dp[i] + 1 < dp[j]:
                    dp[j] = dp[i] + 1

        return dp[n] if dp[n] != INF else -1

