class Solution:
    def maxMoves(self, kx: int, ky: int, positions: List[List[int]]) -> int:
        n = len(positions)
        # All positions: pawns (0..n-1), knight start (n)
        all_pos = [tuple(p) for p in positions] + [(kx, ky)]

        def bfs(sx, sy):
            d = [[-1] * 50 for _ in range(50)]
            d[sx][sy] = 0
            q = deque([(sx, sy)])
            while q:
                x, y = q.popleft()
                for dx, dy in [(-2,-1),(-2,1),(-1,-2),(-1,2),(1,-2),(1,2),(2,-1),(2,1)]:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < 50 and 0 <= ny < 50 and d[nx][ny] == -1:
                        d[nx][ny] = d[x][y] + 1
                        q.append((nx, ny))
            return d

        # Precompute BFS distances from each position
        bfs_results = [bfs(p[0], p[1]) for p in all_pos]

        # dist_mat[i][j] = distance from position i to position j
        dist_mat = [[0] * (n + 1) for _ in range(n + 1)]
        for i in range(n + 1):
            for j in range(n + 1):
                if i != j:
                    dist_mat[i][j] = bfs_results[i][all_pos[j][0]][all_pos[j][1]]

        @lru_cache(maxsize=None)
        def dp(pos, mask, is_alice):
            if mask == 0:
                return 0
            best = 0 if is_alice else float('inf')
            for i in range(n):
                if mask & (1 << i):
                    moves = dist_mat[pos][i] + dp(i, mask ^ (1 << i), not is_alice)
                    if is_alice:
                        best = max(best, moves)
                    else:
                        best = min(best, moves)
            return best

        full_mask = (1 << n) - 1
        return dp(n, full_mask, True)

