class Solution:
    def maximumWeight(self, intervals: List[List[int]]) -> List[int]:
        n = len(intervals)
        indexed = [(intervals[i][0], intervals[i][1], intervals[i][2], i) for i in range(n)]
        indexed.sort(key=lambda x: (x[1], x[0], x[3]))

        ends = [x[1] for x in indexed]

        def better(a, b):
            if a is None:
                return False
            if b is None:
                return True
            if a[0] != b[0]:
                return a[0] > b[0]
            return a[1] < b[1]

        def combine(prev, weight, idx):
            if prev is None:
                return None
            new_indices = sorted(prev[1] + [idx])
            return (prev[0] + weight, new_indices)

        # prefix_best[j][k] = best (max_weight, lex_smallest_indices) for count j
        # considering first k intervals in sorted order
        prefix_best = [[] for _ in range(5)]
        prefix_best[0].append((0, []))
        for j in range(1, 5):
            prefix_best[j].append(None)

        for i in range(n):
            l, r, w, orig_idx = indexed[i]
            # Find rightmost interval with end < l (strict: sharing boundary = overlapping)
            prev_pos = bisect.bisect_left(ends, l) - 1

            dp = [None] * 5
            for j in range(1, 5):
                prev_val = prefix_best[j - 1][prev_pos + 1]
                dp[j] = combine(prev_val, w, orig_idx)

            prefix_best[0].append((0, []))
            for j in range(1, 5):
                prev_best = prefix_best[j][-1]
                if better(dp[j], prev_best):
                    prefix_best[j].append(dp[j])
                else:
                    prefix_best[j].append(prev_best)

        result = (0, [])
        for j in range(1, 5):
            val = prefix_best[j][n]
            if better(val, result):
                result = val

        return result[1]

