class Solution:
    def maxScore(self, grid: List[List[int]]) -> int:
        # Collect all unique values and map to bit positions
        all_values = set()
        for row in grid:
            for val in row:
                all_values.add(val)

        val_to_bit = {v: i for i, v in enumerate(sorted(all_values))}

        # For each row, get unique (value, bit) pairs
        row_values = []
        for row in grid:
            seen = set()
            unique = []
            for val in row:
                if val not in seen:
                    seen.add(val)
                    unique.append((val, val_to_bit[val]))
            row_values.append(unique)

        # DP: bitmask -> max score
        dp = {0: 0}

        for row_idx in range(len(grid)):
            new_dp = {}
            for mask, score in dp.items():
                # Option: skip this row
                if mask not in new_dp or score > new_dp[mask]:
                    new_dp[mask] = score
                # Option: pick a value from this row
                for val, bit in row_values[row_idx]:
                    if mask & (1 << bit) == 0:
                        new_mask = mask | (1 << bit)
                        new_score = score + val
                        if new_mask not in new_dp or new_score > new_dp[new_mask]:
                            new_dp[new_mask] = new_score
            dp = new_dp

        return max(dp.values())

