class Solution:
    def maxValue(self, nums: List[int], k: int) -> int:
        n = len(nums)

        # dp_left[i][j] = set of possible OR values choosing j elements from nums[0..i-1]
        dp_left = [[set() for _ in range(k + 1)] for _ in range(n + 1)]
        dp_left[0][0].add(0)

        for i in range(n):
            for j in range(k + 1):
                dp_left[i + 1][j] |= dp_left[i][j]
                if j > 0:
                    for x in dp_left[i][j - 1]:
                        dp_left[i + 1][j].add(x | nums[i])

        # dp_right[i][j] = set of possible OR values choosing j elements from nums[i..n-1]
        dp_right = [[set() for _ in range(k + 1)] for _ in range(n + 1)]
        dp_right[n][0].add(0)

        for i in range(n - 1, -1, -1):
            for j in range(k + 1):
                dp_right[i][j] |= dp_right[i + 1][j]
                if j > 0:
                    for x in dp_right[i + 1][j - 1]:
                        dp_right[i][j].add(x | nums[i])

        ans = 0
        for i in range(k, n - k + 1):
            for a in dp_left[i][k]:
                for b in dp_right[i][k]:
                    val = a ^ b
                    if val > ans:
                        ans = val

        return ans

