class Solution:
    def minStartingIndex(self, s: str, pattern: str) -> int:
        n, m = len(s), len(pattern)

        def z_function(t):
            z = [0] * len(t)
            l, r = 0, 0
            for i in range(1, len(t)):
                if i < r:
                    z[i] = min(r - i, z[i - l])
                while i + z[i] < len(t) and t[z[i]] == t[i + z[i]]:
                    z[i] += 1
                if i + z[i] > r:
                    l, r = i, i + z[i]
            return z

        # LCP: longest common prefix of s[i:] and pattern
        combined1 = pattern + '$' + s
        z1 = z_function(combined1)

        # LCS: longest common suffix of s[i:i+m] and pattern
        combined2 = pattern[::-1] + '$' + s[::-1]
        z2 = z_function(combined2)

        for i in range(n - m + 1):
            lcp = z1[m + 1 + i]
            if lcp >= m:
                return i
            lcs = z2[m + 1 + (n - m - i)]
            if lcp + lcs >= m - 1:
                return i

        return -1

