class Solution:
    def countWinningSequences(self, s: str) -> int:
        MOD = 10**9 + 7
        n = len(s)

        ci = {'F': 0, 'W': 1, 'E': 2}
        # delta[bob_creature][alice_creature] = score change for Bob
        delta = [[0, -1, 1], [1, 0, -1], [-1, 1, 0]]

        offset = n
        size = 2 * n + 1

        dp = [[0] * size for _ in range(3)]

        a0 = ci[s[0]]
        for j in range(3):
            dp[j][delta[j][a0] + offset] = 1

        for i in range(1, n):
            ai = ci[s[i]]
            new_dp = [[0] * size for _ in range(3)]
            lo = offset - i
            hi = offset + i
            for j in range(3):
                d = delta[j][ai]
                for prev in range(3):
                    if prev == j:
                        continue
                    for sc in range(lo, hi + 1):
                        v = dp[prev][sc]
                        if v:
                            new_dp[j][sc + d] = (new_dp[j][sc + d] + v) % MOD
            dp = new_dp

        ans = 0
        for j in range(3):
            for sc in range(offset + 1, size):
                ans = (ans + dp[j][sc]) % MOD

        return ans

