class Solution:
    def maxScore(self, nums: List[int]) -> int:
        def lcm(a, b):
            return a * b // gcd(a, b)

        def compute_score(arr):
            if not arr:
                return 0
            g = reduce(gcd, arr)
            l = reduce(lcm, arr)
            return g * l

        n = len(nums)
        if n == 0:
            return 0

        best = compute_score(nums)

        for i in range(n):
            remaining = nums[:i] + nums[i+1:]
            if remaining:
                score = compute_score(remaining)
                best = max(best, score)

        return best

