class Solution:
    def findXSum(self, nums: List[int], k: int, x: int) -> List[int]:
        n = len(nums)
        result = []
        for i in range(n - k + 1):
            window = nums[i:i + k]
            freq = Counter(window)
            distinct = len(freq)
            if distinct <= x:
                result.append(sum(window))
            else:
                sorted_elements = sorted(freq.keys(), key=lambda v: (-freq[v], -v))
                top_x = set(sorted_elements[:x])
                s = 0
                for val in top_x:
                    s += val * freq[val]
                result.append(s)
        return result

