class Solution:
    def maxAmount(self, initialCurrency: str, pairs1: List[List[str]], rates1: List[float], pairs2: List[List[str]], rates2: List[float]) -> float:
        # Day 1: BFS to find max amount of each currency from 1.0 initialCurrency
        graph1 = defaultdict(list)
        for (s, t), r in zip(pairs1, rates1):
            graph1[s].append((t, r))
            graph1[t].append((s, 1.0 / r))

        amounts = {initialCurrency: 1.0}
        queue = deque([initialCurrency])
        while queue:
            curr = queue.popleft()
            for nxt, rate in graph1[curr]:
                new_amt = amounts[curr] * rate
                if nxt not in amounts or new_amt > amounts[nxt]:
                    amounts[nxt] = new_amt
                    queue.append(nxt)

        # Day 2: for each currency from day 1, BFS to find max initialCurrency
        graph2 = defaultdict(list)
        for (s, t), r in zip(pairs2, rates2):
            graph2[s].append((t, r))
            graph2[t].append((s, 1.0 / r))

        best = 1.0
        for curr, amt in amounts.items():
            amounts2 = {curr: amt}
            q2 = deque([curr])
            while q2:
                c = q2.popleft()
                for nxt, rate in graph2[c]:
                    new_amt = amounts2[c] * rate
                    if nxt not in amounts2 or new_amt > amounts2[nxt]:
                        amounts2[nxt] = new_amt
                        q2.append(nxt)
            if initialCurrency in amounts2:
                best = max(best, amounts2[initialCurrency])

        return best

