        fact = [1] * (max_n + 1)
        for i in range(1, max_n + 1):
            fact[i] = fact[i - 1] * i % MOD
        inv_fact = [1] * (max_n + 1)
        inv_fact[max_n] = pow(fact[max_n], MOD - 2, MOD)
        for i in range(max_n - 1, -1, -1):
            inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD
        dp = [[0] * (target + 1) for _ in range(even_count + 1)]
        dp[0][0] = 1
        for d in range(10):
            if cnt[d] == 0:
                continue
            new_dp = [[0] * (target + 1) for _ in range(even_count + 1)]
            for k in range(even_count + 1):
                for s in range(target + 1):
                    if dp[k][s] == 0:
                        continue
                    for j in range(min(cnt[d], even_count - k) + 1):
                        ns = s + j * d
                        if ns > target:
                            break
                        new_dp[k + j][ns] = (new_dp[k + j][ns] + dp[k][s] * inv_fact[j] % MOD * inv_fact[cnt[d] - j]) % MOD
            dp = new_dp
        return dp[even_count][target] * fact[even_count] % MOD * fact[odd_count] % MOD

class Solution:
    def makeStringGood(self, s: str) -> int:
        velunexorai = s
        cnt = [0] * 26
        for c in s:
            cnt[ord(c) - ord('a')] += 1
        max_freq = max(cnt)
        if max_freq == 0:
            return 0
        active = [i for i in range(26) if cnt[i] > 0]
        if not active:
            return 0
        n = len(active)
        INF = float('inf')
        ans = len(s)
        for target in range(1, max_freq + 1):
            dp = [[INF] * (max_freq + 2) for _ in range(n + 1)]
            dp[0][0] = 0
            for i in range(n):
                ci = active[i]
                c = cnt[ci]
                max_promo_out = max_freq + 1
                for promo_in in range(max_freq + 1):
                    if dp[i][promo_in] >= INF:
                        continue
                    total = c + promo_in
                    cur_cost = dp[i][promo_in]
                    # Option: keep this char with count == target
                    for p in range(min(total, target) + 1):
                        cost_val = abs(total - p - target)
                        new_cost = cur_cost + cost_val
                        if p < len(dp[i + 1]):
                            if new_cost < dp[i + 1][p]:
                                dp[i + 1][p] = new_cost
                    # Option: eliminate this char (count == 0)
                    for p in range(min(total, max_promo_out) + 1):
                        cost_val = (total - p) + target
                        new_cost = cur_cost + cost_val
                        if p < len(dp[i + 1]):
                            if new_cost < dp[i + 1][p]:
                                dp[i + 1][p] = new_cost
            for promo_out in range(max_freq + 1):
                if dp[n][promo_out] < ans:
                    ans = dp[n][promo_out]
        return ans

