class Solution:
    def minArraySum(self, nums: List[int], k: int, op1: int, op2: int) -> int:
        INF = float('inf')
        dp = [[INF] * (op2 + 1) for _ in range(op1 + 1)]
        dp[0][0] = 0

        for num in nums:
            new_dp = [[INF] * (op2 + 1) for _ in range(op1 + 1)]
            for j in range(op1 + 1):
                for l in range(op2 + 1):
                    if dp[j][l] == INF:
                        continue
                    # Do nothing
                    new_dp[j][l] = min(new_dp[j][l], dp[j][l] + num)
                    # Apply op1 only (ceil divide by 2)
                    if j < op1:
                        val = (num + 1) // 2
                        new_dp[j + 1][l] = min(new_dp[j + 1][l], dp[j][l] + val)
                    # Apply op2 only (subtract k)
                    if l < op2 and num >= k:
                        new_dp[j][l + 1] = min(new_dp[j][l + 1], dp[j][l] + num - k)
                    # Apply both op1 and op2
                    if j < op1 and l < op2:
                        # Order: op2 then op1
                        if num >= k:
                            after_op2 = num - k
                            val = (after_op2 + 1) // 2
                            new_dp[j + 1][l + 1] = min(new_dp[j + 1][l + 1], dp[j][l] + val)
                        # Order: op1 then op2
                        after_op1 = (num + 1) // 2
                        if after_op1 >= k:
                            new_dp[j + 1][l + 1] = min(new_dp[j + 1][l + 1], dp[j][l] + after_op1 - k)
            dp = new_dp

        result = INF
        for j in range(op1 + 1):
            for l in range(op2 + 1):
                result = min(result, dp[j][l])
        return result

import heapq

class Solution:
    def minOperations(self, n: int, m: int) -> int:
        limit = 10000
        is_prime = [True] * limit
        is_prime[0] = is_prime[1] = False
        for i in range(2, int(limit ** 0.5) + 1):
            if is_prime[i]:
                for j in range(i * i, limit, i):
                    is_prime[j] = False

        if is_prime[n] or is_prime[m]:
            return -1

        d = len(str(n))

        dist = {n: n}
        pq = [(n, n)]

        while pq:
            cost, val = heapq.heappop(pq)
            if val == m:
                return cost
            if cost > dist.get(val, float('inf')):
                continue

            s = str(val)
            for i in range(d):
                digit = int(s[i])
                for delta in (-1, 1):
                    nd = digit + delta
                    if nd < 0 or nd > 9:
                        continue
                    ns = s[:i] + str(nd) + s[i + 1:]
                    nv = int(ns)
                    if len(str(nv)) != d:
                        continue
                    if is_prime[nv]:
                        continue
                    nc = cost + nv
                    if nc < dist.get(nv, float('inf')):
                        dist[nv] = nc
                        heapq.heappush(pq, (nc, nv))

        return -1

