class Solution:
    def minDifference(self, nums: List[int]) -> int:
        n = len(nums)

        # All -1: can fill with same value
        if all(x == -1 for x in nums):
            return 0

        # No -1: answer is max adjacent difference
        if all(x != -1 for x in nums):
            return max(abs(nums[i] - nums[i + 1]) for i in range(n - 1))

        lo, hi = 0, 10 ** 9

        def check(d):
            # Check adjacent known pairs
            for i in range(n - 1):
                if nums[i] != -1 and nums[i + 1] != -1:
                    if abs(nums[i] - nums[i + 1]) > d:
                        return False

            # Collect constraint intervals for -1s with known neighbors
            intervals = []
            for i in range(n):
                if nums[i] == -1:
                    lo_v, hi_v = 1, 10 ** 9
                    has_constraint = False
                    if i > 0 and nums[i - 1] != -1:
                        lo_v = max(lo_v, nums[i - 1] - d)
                        hi_v = min(hi_v, nums[i - 1] + d)
                        has_constraint = True
                    if i < n - 1 and nums[i + 1] != -1:
                        lo_v = max(lo_v, nums[i + 1] - d)
                        hi_v = min(hi_v, nums[i + 1] + d)
                        has_constraint = True
                    if has_constraint:
                        if lo_v > hi_v:
                            return False
                        intervals.append((lo_v, hi_v))

            if not intervals:
                return True

            # Single point check
            common_lo = max(iv[0] for iv in intervals)
            common_hi = min(iv[1] for iv in intervals)
            if common_lo <= common_hi:
                return True

            # Two points check with |x - y| <= d
            intervals.sort()
            m = len(intervals)

            pref_minR = [0] * m
            pref_minR[0] = intervals[0][1]
            for i in range(1, m):
                pref_minR[i] = min(pref_minR[i - 1], intervals[i][1])

            suff_minR = [10 ** 18] * (m + 1)
            for i in range(m - 1, -1, -1):
                suff_minR[i] = min(intervals[i][1], suff_minR[i + 1])

            for k in range(1, m):
                left_lo = intervals[k - 1][0]
                left_hi = pref_minR[k - 1]
                right_lo = intervals[k][0]
                right_hi = suff_minR[k]

                if left_lo > left_hi or right_lo > right_hi:
                    continue

                min_diff = left_lo - right_hi
                max_diff = left_hi - right_lo

                if min_diff <= d and max_diff >= -d:
                    return True

            return False

        while lo < hi:
            mid = (lo + hi) // 2
            if check(mid):
                hi = mid
            else:
                lo = mid + 1

        return lo

