class Solution:
    def countPathsWithXorValue(self, grid: List[List[int]], k: int) -> int:
        MOD = 10**9 + 7
        m = len(grid)
        n = len(grid[0])
        prev = [[0] * 16 for _ in range(n)]
        for i in range(m):
            curr = [[0] * 16 for _ in range(n)]
            for j in range(n):
                val = grid[i][j]
                if i == 0 and j == 0:
                    curr[j][val] = 1
                else:
                    for x in range(16):
                        new_x = x ^ val
                        if j > 0:
                            curr[j][new_x] = (curr[j][new_x] + curr[j - 1][x]) % MOD
                        if i > 0:
                            curr[j][new_x] = (curr[j][new_x] + prev[j][x]) % MOD
            prev = curr
        return prev[n - 1][k] % MOD

