        m, n = len(coins), len(coins[0])
        NEG_INF = float('-inf')
        dp = [[NEG_INF] * 3 for _ in range(n)]
        for i in range(m):
            new_dp = [[NEG_INF] * 3 for _ in range(n)]
            for j in range(n):
                val = coins[i][j]
                for k in range(3):
                    prev = NEG_INF
                    if i == 0 and j == 0:
                        if k == 0:
                            prev = 0
                    else:
                        if i > 0:
                            prev = max(prev, dp[j][k])
                        if j > 0:
                            prev = max(prev, new_dp[j - 1][k])
                    if prev == NEG_INF:
                        continue
                    if val >= 0:
                        new_dp[j][k] = max(new_dp[j][k], prev + val)
                    else:
                        new_dp[j][k] = max(new_dp[j][k], prev + val)
                        if k + 1 <= 2:
                            new_dp[j][k + 1] = max(new_dp[j][k + 1], prev)
            dp = new_dp
        return max(dp[n - 1])

