class Solution:
    def countComponents(self, nums: List[int], threshold: int) -> int:
        small = []
        large_count = 0

        for v in nums:
            if v <= threshold:
                small.append(v)
            else:
                large_count += 1

        if not small:
            return large_count

        n = len(small)

        parent = list(range(n))
        rnk = [0] * n

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(x, y):
            rx, ry = find(x), find(y)
            if rx == ry:
                return
            if rnk[rx] < rnk[ry]:
                rx, ry = ry, rx
            parent[ry] = rx
            if rnk[rx] == rnk[ry]:
                rnk[rx] += 1

        first_at = [-1] * (threshold + 1)

        for idx, v in enumerate(small):
            for m in range(v, threshold + 1, v):
                if first_at[m] != -1:
                    union(idx, first_at[m])
                else:
                    first_at[m] = idx

        roots = set()
        for i in range(n):
            roots.add(find(i))

        return len(roots) + large_count

