        for i in range(n - 1, -1, -1):
            for j in range(n - 1, -1, -1):
                if nums[i] == nums[j]:
                    lcp[i][j] = 1
                    if i + 1 < n and j + 1 < n:
                        lcp[i][j] += lcp[i + 1][j + 1]

        count = 0
        for i in range(1, n - 1):
            for j in range(i + 1, n):
                len1 = i
                len2 = j - i
                len3 = n - j

                if lcp[0][i] >= len1 and len1 <= len2:
                    count += 1
                elif lcp[i][j] >= len2 and len2 <= len3:
                    count += 1

        return count

class Solution:
    def minLength(self, s: str, numOps: int) -> int:
        n = len(s)

        # Compute maximal runs of identical characters
        runs = []
        i = 0
        while i < n:
            j = i
            while j < n and s[j] == s[i]:
                j += 1
            runs.append(j - i)
            i = j

        max_run = max(runs)

        # Binary search on the answer
        lo, hi = 1, max_run

        def check(mid):
            ops = 0
            for L in runs:
                ops += L // (mid + 1)
            return ops <= numOps

        while lo < hi:
            mid = (lo + hi) // 2
            if check(mid):
                hi = mid
            else:
                lo = mid + 1

        return lo

class Solution:
    def shortestMatchingSubstring(self, s: str, p: str) -> int:
        parts = p.split('*')
        A, B, C = parts[0], parts[1], parts[2]
        n = len(s)
        len_a, len_b, len_c = len(A), len(B), len(C)

        def find_all(pattern, text):
            if not pattern:
                return list(range(len(text) + 1))
            m = len(pattern)
            fail = [0] * m
            j = 0
            for i in range(1, m):
                while j > 0 and pattern[i] != pattern[j]:
                    j = fail[j - 1]
                if pattern[i] == pattern[j]:
                    j += 1
                fail[i] = j
            positions = []
            j = 0
            for i in range(len(text)):
                while j > 0 and text[i] != pattern[j]:
                    j = fail[j - 1]
                if text[i] == pattern[j]:
                    j += 1
                if j == m:
                    positions.append(i - m + 1)
                    j = fail[j - 1]
            return positions

        def build_next(pattern, text):
            positions = find_all(pattern, text)
            pos_set = set(positions)
            tn = len(text)
            next_arr = [-1] * (tn + 2)
            for i in range(tn, -1, -1):
                if i in pos_set:
                    next_arr[i] = i
                else:
                    next_arr[i] = next_arr[i + 1]
            return next_arr

        next_b = build_next(B, s)
        next_c = build_next(C, s)

        a_positions = find_all(A, s)

        ans = float('inf')

        for i in a_positions:
            bi = i + len_a
            if bi > n:
                continue
            b_start = next_b[bi]
            if b_start == -1:
                continue
            ci = b_start + len_b
            if ci > n:
                continue
            c_start = next_c[ci]
            if c_start == -1:
                continue
            total = c_start + len_c - i
            ans = min(ans, total)

        return ans if ans != float('inf') else -1

class Solution:
    def countSubstrings(self, s: str) -> int:
        n = len(s)
        ans = 0

        # Digit sum prefix for d=3,6,9
        dpre = [0] * (n + 1)
        for i in range(n):
            dpre[i + 1] = dpre[i] + int(s[i])

        # d in {1, 2, 5}: trivially all valid
        for j in range(n):
            d = int(s[j])
            if d == 1 or d == 2 or d == 5:
                ans += j + 1

        # d in {3, 6}: digit sum mod 3
        cnt3 = {0: 1}
        for j in range(n):
            r = dpre[j + 1] % 3
            if s[j] == '3' or s[j] == '6':
                ans += cnt3.get(r, 0)
            cnt3[r] = cnt3.get(r, 0) + 1

        # d = 4: last 2 digits determine divisibility by 4
        for j in range(n):
            if s[j] == '4':
                ans += 1
                if j >= 1 and (int(s[j - 1]) * 10 + 4) % 4 == 0:
                    ans += j

        # d = 7: normalized prefix with modular inverse of 10 mod 7
        inv10 = 5  # pow(10, -1, 7) = 5
        cnt7 = {0: 1}
        N = 0
        pw = inv10
        for k in range(n):
            N = (N + int(s[k]) * pw) % 7
            if s[k] == '7':
                ans += cnt7.get(N, 0)
            cnt7[N] = cnt7.get(N, 0) + 1
            pw = pw * inv10 % 7

        # d = 8: last 3 digits determine divisibility by 8
        for j in range(n):
            if s[j] == '8':
                ans += 1
                if j >= 1:
                    v2 = int(s[j - 1]) * 10 + 8
                    if v2 % 8 == 0:
                        ans += 1
                if j >= 2:
                    v3 = int(s[j - 2]) * 100 + int(s[j - 1]) * 10 + 8
                    if v3 % 8 == 0:
                        ans += j - 1

        # d = 9: digit sum mod 9
        cnt9 = {0: 1}
        for j in range(n):
            r = dpre[j + 1] % 9
            if s[j] == '9':
                ans += cnt9.get(r, 0)
            cnt9[r] = cnt9.get(r, 0) + 1

        return ans

