class Solution:
    def longestSubsequence(self, nums: list) -> int:
        MAX_VAL = 300
        MAX_DIFF = 300

        # dp[v][d] = max length of valid subsequence ending at value v with last diff d
        dp = [[0] * (MAX_DIFF + 1) for _ in range(MAX_VAL + 1)]
        # suf[v][d] = max(dp[v][d], dp[v][d+1], ..., dp[v][MAX_DIFF])
        suf = [[0] * (MAX_DIFF + 1) for _ in range(MAX_VAL + 1)]

        ans = 0

        for x in nums:
            new_dp = [0] * (MAX_DIFF + 1)
            new_dp[MAX_DIFF] = 1  # single element subsequence

            for v in range(1, MAX_VAL + 1):
                diff = abs(x - v)
                if suf[v][diff] > 0:
                    val = suf[v][diff] + 1
                    if val > new_dp[diff]:
                        new_dp[diff] = val

            # Update dp[x] with element-wise max
            for d in range(MAX_DIFF + 1):
                if new_dp[d] > dp[x][d]:
                    dp[x][d] = new_dp[d]

            # Recompute suffix max for value x
            suf[x][MAX_DIFF] = dp[x][MAX_DIFF]
            for d in range(MAX_DIFF - 1, -1, -1):
                suf[x][d] = dp[x][d] if dp[x][d] > suf[x][d + 1] else suf[x][d + 1]

            if suf[x][0] > ans:
                ans = suf[x][0]

        return ans

class Solution:
    def countMentions(self, numberOfUsers: int, events: list) -> list:
        mentions = [0] * numberOfUsers
        online_until = [0] * numberOfUsers

        sorted_events = []
        for event in events:
            ts = int(event[1])
            type_order = 0 if event[0] == "OFFLINE" else 1
            sorted_events.append((ts, type_order, event))

        sorted_events.sort()

        for ts, _, event in sorted_events:
            if event[0] == "OFFLINE":
                user_id = int(event[2])
                online_until[user_id] = ts + 60
            elif event[0] == "MESSAGE":
                mention_str = event[2]
                tokens = mention_str.split()
                for token in tokens:
                    if token == "ALL":
                        for i in range(numberOfUsers):
                            mentions[i] += 1
                    elif token == "HERE":
                        for i in range(numberOfUsers):
                            if online_until[i] <= ts:
                                mentions[i] += 1
                    elif token.startswith("id"):
                        user_id = int(token[2:])
                        mentions[user_id] += 1

        return mentions

class Solution:
    def maxSum(self, nums: list, k: int, m: int) -> int:
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]

        NEG_INF = float('-inf')
        dp = [0] * (n + 1)

        for j in range(1, k + 1):
            new_dp = [NEG_INF] * (n + 1)
            best = NEG_INF
            for i in range(n + 1):
                if i > 0:
                    new_dp[i] = max(new_dp[i], new_dp[i - 1])
                if i >= m:
                    s = i - m
                    if dp[s] != NEG_INF:
                        best = max(best, dp[s] - prefix[s])
                    if best != NEG_INF:
                        new_dp[i] = max(new_dp[i], prefix[i] + best)
            dp = new_dp

        return dp[n]

class Solution:
    def sumOfGoodNumbers(self, nums: list, k: int) -> int:
        n = len(nums)
        total = 0
        for i in range(n):
            good = True
            if i - k >= 0 and nums[i] <= nums[i - k]:
                good = False
            if i + k < n and nums[i] <= nums[i + k]:
                good = False
            if good:
                total += nums[i]
        return total

class Solution:
    def subarraySum(self, nums: list) -> int:
        n = len(nums)
        prefix = [0] * (n + 1)
        for i in range(n):
            prefix[i + 1] = prefix[i] + nums[i]
        total = 0
        for i in range(n):
            start = max(0, i - nums[i])
            total += prefix[i + 1] - prefix[start]
        return total

class Solution:
    def lenOfVDiagonal(self, grid: list) -> int:
        n = len(grid)
        m = len(grid[0])

        # Directions in clockwise order: DR, DL, UL, UR
        dirs = [(1, 1), (1, -1), (-1, -1), (-1, 1)]

        memo = {}

        def dfs(r, c, d, turned, expect_two):
            key = (r, c, d, turned, expect_two)
            if key in memo:
                return memo[key]

            exp_val = 2 if expect_two else 0
            dr, dc = dirs[d]
            nr, nc = r + dr, c + dc

            best = 0

            # Continue in same direction
            if 0 <= nr < n and 0 <= nc < m and grid[nr][nc] == exp_val:
                best = max(best, 1 + dfs(nr, nc, d, turned, not expect_two))

            # Turn clockwise (at most once)
            if not turned:
                nd = (d + 1) % 4
                ndr, ndc = dirs[nd]
                nnr, nnc = r + ndr, c + ndc
                if 0 <= nnr < n and 0 <= nnc < m and grid[nnr][nnc] == exp_val:
                    best = max(best, 1 + dfs(nnr, nnc, nd, True, not expect_two))

            memo[key] = best
            return best

        ans = 0
        for r in range(n):
            for c in range(m):
                if grid[r][c] == 1:
                    best_from_here = 1
                    for d in range(4):
                        dr, dc = dirs[d]
                        nr, nc = r + dr, c + dc
                        if 0 <= nr < n and 0 <= nc < m and grid[nr][nc] == 2:
                            best_from_here = max(best_from_here, 2 + dfs(nr, nc, d, False, False))
                    ans = max(ans, best_from_here)

        return ans

class Solution:
    def findValidPair(self, s: str) -> str:
