class Solution:
    def distanceSum(self, m: int, n: int, k: int) -> int:
        MOD = 10**9 + 7

        def modinv(x):
            return pow(x, MOD - 2, MOD)

        def comb(N, R):
            if R < 0 or R > N:
                return 0
            if R == 0:
                return 1
            num = 1
            den = 1
            for i in range(R):
                num = num * (N - i) % MOD
                den = den * (i + 1) % MOD
            return num * modinv(den) % MOD

        inv6 = modinv(6)

        # sum_{d=1}^{m-1} d*(m-d) = m*(m^2-1)/6
        row_sum = m * ((m * m - 1) % MOD) % MOD * inv6 % MOD
        col_sum = n * ((n * n - 1) % MOD) % MOD * inv6 % MOD

        # Total Manhattan distance sum over all pairs of cells
        S = (n * n % MOD * row_sum + m * m % MOD * col_sum) % MOD

        # Each pair appears in C(mn-2, k-2) arrangements
        C = comb(m * n - 2, k - 2)

        return S * C % MOD

