class Solution:
    def sortMatrix(self, grid: List[List[int]]) -> List[List[int]]:
        n = len(grid)
        # Group elements by diagonal (i - j)
        diagonals = {}
        positions = {}
        for i in range(n):
            for j in range(n):
                key = i - j
                if key not in diagonals:
                    diagonals[key] = []
                    positions[key] = []
                diagonals[key].append(grid[i][j])
                positions[key].append((i, j))

        # Sort each diagonal
        for key in diagonals:
            if key >= 0:
                diagonals[key].sort(reverse=True)  # non-increasing
            else:
                diagonals[key].sort()  # non-decreasing

            # Place back
            for idx, (i, j) in enumerate(positions[key]):
                grid[i][j] = diagonals[key][idx]

        return grid

