class Solution:
    def maxFrequency(self, nums: List[int], k: int) -> int:
        base_k = nums.count(k)
        best = 0
        for v in range(1, 51):
            if v == k:
                continue
            max_ending = 0
            max_sum = 0
            for x in nums:
                if x == v:
                    max_ending += 1
                elif x == k:
                    max_ending -= 1
                if max_ending < 0:
                    max_ending = 0
                if max_ending > max_sum:
                    max_sum = max_ending
            if max_sum > best:
                best = max_sum
        return base_k + best

