class Solution:
    def maxDistance(self, s: str, k: int) -> int:
        n_count = s_count = e_count = w_count = 0
        result = 0
        for c in s:
            if c == 'N':
                n_count += 1
            elif c == 'S':
                s_count += 1
            elif c == 'E':
                e_count += 1
            elif c == 'W':
                w_count += 1
            wasted = min(n_count, s_count) + min(e_count, w_count)
            fixes = min(k, wasted)
            manhattan = (n_count + s_count + e_count + w_count) - 2 * wasted + 2 * fixes
            result = max(result, manhattan)
        return result

class Solution:
    def assignElements(self, groups: list[int], elements: list[int]) -> list[int]:
        # Map each unique element value to its smallest index
        element_map = {}
        for j, val in enumerate(elements):
            if val not in element_map:
                element_map[val] = j

        result = []
        for g in groups:
            best = -1
            d = 1
            while d * d <= g:
                if g % d == 0:
                    if d in element_map:
                        idx = element_map[d]
                        if best == -1 or idx < best:
                            best = idx
                    other = g // d
                    if other != d and other in element_map:
                        idx = element_map[other]
                        if best == -1 or idx < best:
                            best = idx
                d += 1
            result.append(best)
        return result

class Solution:
    def maxScore(self, points: list[int], m: int) -> int:
        n = len(points)

        def check(target):
            if target <= 0:
                return True
            total = 0
            carry = 0
            for i in range(n):
                need_i = (target + points[i] - 1) // points[i]
                have = 1 + carry
                if i == n - 1:
                    if carry >= need_i:
                        pass
                    else:
                        total += 1
                        remaining = need_i - have
                        if remaining > 0:
                            total += remaining * 2
                else:
                    if have >= need_i:
                        total += 1
                        carry = 0
                    else:
                        deficit = need_i - have
                        total += 1 + deficit * 2
                        carry = deficit
                if total > m:
                    return False
            return total <= m

        lo, hi = 0, m * max(points)
        while lo < hi:
            mid = (lo + hi + 1) // 2
            if check(mid):
                lo = mid
            else:
                hi = mid - 1
        return lo

