class Solution:
    def minimumCost(self, nums: List[int], cost: List[int], k: int) -> int:
        n = len(nums)
        ps = [0] * (n + 1)
        pc = [0] * (n + 1)
        for i in range(n):
            ps[i + 1] = ps[i] + nums[i]
            pc[i + 1] = pc[i] + cost[i]

        INF = float('inf')
        prev = [INF] * (n + 1)
        prev[0] = 0
        best = INF

        for t in range(1, n + 1):
            dq_m = []
            dq_b = []
            head = 0
            curr = [INF] * (n + 1)
            any_valid = False

            for j in range(t, n + 1):
                mi = -pc[j - 1]
                bi = prev[j - 1]
                if bi < INF:
                    while len(dq_m) - head >= 2:
                        m1, b1 = dq_m[-2], dq_b[-2]
                        m2, b2 = dq_m[-1], dq_b[-1]
                        if (bi - b1) * (m1 - m2) <= (b2 - b1) * (m1 - mi):
                            dq_m.pop()
                            dq_b.pop()
                        else:
                            break
                    dq_m.append(mi)
                    dq_b.append(bi)

                if len(dq_m) - head >= 1:
                    x = ps[j] + k * t
                    while len(dq_m) - head >= 2:
                        if dq_m[head + 1] * x + dq_b[head + 1] <= dq_m[head] * x + dq_b[head]:
                            head += 1
                        else:
                            break
                    val = dq_m[head] * x + dq_b[head]
                    curr[j] = (ps[j] + k * t) * pc[j] + val
                    any_valid = True

            if curr[n] < best:
                best = curr[n]
            prev = curr

            if not any_valid:
                break

        return int(best)

