        while len(digits) > 2:
            new_digits = []
            for i in range(len(digits) - 1):
                new_digits.append((digits[i] + digits[i + 1]) % 10)
            digits = new_digits
        return digits[0] == digits[1]

class Solution:
    def generateString(self, str1: str, str2: str) -> str:
        n = len(str1)
        m = len(str2)
        L = n + m - 1

        word = ['a'] * L
        locked = [False] * L

        # Apply 'T' constraints first
        for i in range(n):
            if str1[i] == 'T':
                for j in range(m):
                    pos = i + j
                    if locked[pos]:
                        if word[pos] != str2[j]:
                            return ""
                    else:
                        word[pos] = str2[j]
                        locked[pos] = True

        # Fix 'F' constraints iteratively
        changed = True
        while changed:
            changed = False
            for i in range(n):
                if str1[i] == 'F':
                    match = True
                    for j in range(m):
                        if word[i + j] != str2[j]:
                            match = False
                            break
                    if match:
                        found = -1
                        for j in range(m - 1, -1, -1):
                            pos = i + j
                            if not locked[pos] and word[pos] < 'z':
                                found = pos
                                break
                        if found == -1:
                            return ""
                        word[found] = chr(ord(word[found]) + 1)
                        changed = True

        return ''.join(word)

class Solution:
    def maxSubstringLength(self, s: str, k: int) -> bool:
        if k == 0:
            return True
        n = len(s)
        first = {}
        last = {}
        for i, c in enumerate(s):
            if c not in first:
                first[c] = i
            last[c] = i
        valid_intervals = []
        start_positions = sorted(set(first.values()))
        for l in start_positions:
            r = l
            ok = True
            i = l
            while i <= r:
                c = s[i]
                if first[c] < l:
                    ok = False
                    break
                if last[c] > r:
                    r = last[c]
                i += 1
            if ok and (l > 0 or r < n - 1):
                valid_intervals.append((l, r))
        valid_intervals = sorted(set(valid_intervals), key=lambda x: x[1])
        count = 0
        last_end = -1
        for l, r in valid_intervals:
            if l > last_end:
                count += 1
                last_end = r
        return count >= k

class Solution:
    def minimumPairRemoval(self, nums: list[int]) -> int:
        n = len(nums)
        ops = 0
        arr = list(nums)
        while True:
            non_decreasing = True
            for i in range(len(arr) - 1):
                if arr[i] > arr[i + 1]:
                    non_decreasing = False
                    break
            if non_decreasing:
                break
            min_sum = float('inf')
            min_idx = 0
            for i in range(len(arr) - 1):
                s = arr[i] + arr[i + 1]
                if s < min_sum:
                    min_sum = s
                    min_idx = i
            arr[min_idx] = arr[min_idx] + arr[min_idx + 1]
            arr.pop(min_idx + 1)
            ops += 1
        return ops

class Solution:
    def minCost(self, nums: list[int]) -> int:
        n = len(nums)
        if n <= 2:
            return max(nums)

        from functools import lru_cache

        @lru_cache(maxsize=None)
        def dp(surv, nxt):
            if surv == -1:
                remaining = n - nxt
            else:
                remaining = 1 + n - nxt

            if remaining == 0:
                return 0
            if remaining == 1:
                return nums[surv] if surv != -1 else nums[nxt]
            if remaining == 2:
                if surv != -1:
                    return max(nums[surv], nums[nxt])
                else:
                    return max(nums[nxt], nums[nxt + 1])

            if surv == -1:
                a, b, c = nums[nxt], nums[nxt + 1], nums[nxt + 2]
                return min(
                    max(a, b) + dp(nxt + 2, nxt + 3),
                    max(a, c) + dp(nxt + 1, nxt + 3),
                    max(b, c) + dp(nxt, nxt + 3)
                )
            else:
                a = nums[surv]
                b, c = nums[nxt], nums[nxt + 1]
                return min(
                    max(a, b) + dp(nxt + 1, nxt + 2),
                    max(a, c) + dp(nxt, nxt + 2),
                    max(b, c) + dp(surv, nxt + 2)
                )

        return dp(-1, 0)

class Solution:
    def maxProduct(self, nums: list[int], k: int, limit: int) -> int:
        # dp = set of (next_is_even, alt_sum, product)
        # next_is_even: True if next element added goes to even position (adds)
        # alt_sum: current alternating sum (even positions - odd positions)
        # product: current product of elements in subsequence
        dp = set()

        for val in nums:
            to_add = []
            for (next_even, asum, prod) in dp:
                new_asum = asum + val if next_even else asum - val
                new_prod = prod * val
                if new_prod <= limit:
                    to_add.append((not next_even, new_asum, new_prod))
            # Start new subsequence with just this element
            if val <= limit:
                to_add.append((False, val, val))
            dp.update(to_add)

        best = -1
        for (_, asum, prod) in dp:
            if asum == k and prod > best:
                best = prod
        return best

