import sys
from collections import deque


def solve():
    input = sys.stdin.readline
    H, W, T = map(int, input().split())
    grid = [input().strip() for _ in range(H)]

    start = goal = None
    candies = []

    for i in range(H):
        for j in range(W):
            if grid[i][j] == 'S':
                start = (i, j)
            elif grid[i][j] == 'G':
                goal = (i, j)
            elif grid[i][j] == 'o':
                candies.append((i, j))

    K = len(candies)

    if K == 0:
        dist = bfs_dist(grid, start[0], start[1], H, W)
        d = dist[goal[0]][goal[1]]
        if d != -1 and d <= T:
            print(0)
        else:
            print(-1)
        return

    nodes = [start, goal] + candies
    N = len(nodes)

    bfs_dists = []
    for r, c in nodes:
        bfs_dists.append(bfs_dist(grid, r, c, H, W))

    dist_m = [[0] * N for _ in range(N)]
    for i in range(N):
        for j in range(N):
            r, c = nodes[j]
            dist_m[i][j] = bfs_dists[i][r][c]

    if dist_m[0][1] == -1:
        print(-1)
        return

    INF = float('inf')
    full = 1 << K
    dp = [[INF] * K for _ in range(full)]

    for i in range(K):
        d = dist_m[0][i + 2]
        if d != -1:
            dp[1 << i][i] = d

    for mask in range(full):
        for i in range(K):
            if not (mask >> i & 1):
                continue
            val = dp[mask][i]
            if val >= INF:
                continue
            not_mask = (full - 1) ^ mask
            nm = not_mask
            while nm:
                lsb = nm & -nm
                j = lsb.bit_length() - 1
                d = dist_m[i + 2][j + 2]
                if d != -1:
                    new_mask = mask | lsb
                    new_val = val + d
                    if new_val < dp[new_mask][j]:
                        dp[new_mask][j] = new_val
                nm ^= lsb

    ans = -1
    if dist_m[0][1] <= T:
        ans = 0

    for mask in range(full):
        cnt = bin(mask).count('1')
        if cnt <= ans:
            continue
        for i in range(K):
            if not (mask >> i & 1):
                continue
            if dp[mask][i] >= INF:
                continue
            d = dist_m[i + 2][1]
            if d != -1 and dp[mask][i] + d <= T:
                ans = max(ans, cnt)
                break

    print(ans)


def bfs_dist(grid, sr, sc, H, W):
    dist = [[-1] * W for _ in range(H)]
    dist[sr][sc] = 0
    q = deque([(sr, sc)])
    while q:
        r, c = q.popleft()
        for dr, dc in ((-1, 0), (1, 0), (0, -1), (0, 1)):
            nr, nc = r + dr, c + dc
            if 0 <= nr < H and 0 <= nc < W and grid[nr][nc] != '#' and dist[nr][nc] == -1:
                dist[nr][nc] = dist[r][c] + 1
                q.append((nr, nc))
    return dist


